```python
D = {0: -1, 1: 2}

def suite(n):
    if n not in D:
        a = suite(n - 2)
        b = suite(n - 1)
        if a <= 0:
            D[n] = 2 * b + a
        else:
            D[n] = b - 3 * a
    return D[n]
```

